  ('dietitian-moex-08061', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '大型餐飲機構為有效清洗髒亂的餐具，希望能將餐盤直接置入洗碗籃中，由輸送帶送進洗碗槽，經清潔 液、熱水、消毒液沖洗後，烘乾再送出，此為：', '["雙槽洗碗機", "三槽洗碗機", "單槽洗碗機", "理想化洗碗機"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "83e883c42452", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
